window.__QUIZ_DATA__=[{"id":"objective>Biology>2022>1","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : PROPERTIES AND FUNCTIONS OF THE LIVING CELL","question":"Which of the following statements about living things is correct?","images":[],"options":{"A":"Animals respire using carbon (IV) oxide as a raw material","B":"Growth in plants is limited after some time","C":"Most plants respond to stimulus slowly","D":"Higher animals can reproduce asexually"},"answer":"C","explanation":"Living things respond to stimuli, and this is one of the characteristics of life. However, the rate of response varies. Plants, for instance, respond to stimuli but at a slower pace compared to animals. This is due to their lack of a nervous system. The other options are incorrect. Animals respire using oxygen, not carbon (IV) oxide. Growth in plants is not necessarily limited after some time, it depends on the species and environmental conditions. Higher animals generally reproduce sexually, not asexually.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>2","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Organ level of organization in living things is found in","images":[],"options":{"A":"waterleaf plant","B":"virus particle","C":"kidney","D":"spermatozoon"},"answer":"C","explanation":"In the level of biological organization, the kidney is an organ. In all animals that have complex levels of organization, a kidney is always an organ","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>3","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Diagrams X and Y below are illustrations of transverse sections of a part of plants. Study them and answer the question below      Which of the following statements is not correct? Diagrams X and Y are sections of","images":["data:image/png;base64,"],"options":{"A":"roots","B":"a dicotyledonous root and a monocotyledonous root respectively","C":"vascular bundles.","D":"stems."},"answer":"D","explanation":"Stem is the main trunk of a plant that bear branches, leaves and fruits","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>4","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Diagrams X and Y below are illustrations of transverse sections of a part of plants. Study them and answer the question below  The part responsible for conducting water and dissolved mineral salts from the soil to the leaves is labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"The xylem is the tissue in plants responsible for the conduction of water and dissolved mineral salts from the roots to the leaves. It consists of various cell types, including tracheids and vessel elements, which are specialized for the upward transport of water and minerals absorbed from the soil. The root, on the other hand, is primarily involved in anchoring the plant and absorbing water and minerals from the soil, but it is not the tissue that conducts these substances to the leaves","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>5","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Diagrams X and Y below are illustrations of transverse sections of a part of plants. Study them and answer the question below  The part labelled II is the","images":["data:image/png;base64,"],"options":{"A":"pith","B":"xylem","C":"phloem","D":"endodermis"},"answer":"A","explanation":"II is the pith. The pith is typically found in the roots of monocot plants but not in the roots of dicot plants. In monocot roots, the pith is a central region of parenchyma cells. In contrast, dicot roots usually have a solid core of vascular tissue without a distinct pith, with xylem and phloem arranged in a radial pattern around a central core.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>6","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The organelles in cells which are also referred to as suicidal bags are the","images":[],"options":{"A":"mitochondria","B":"lysosomes","C":"ribosomes","D":"nuclei"},"answer":"B","explanation":"Lysosomes are called \"suicide bags\" of the cell because they have hydrolytic enzymes stored in them. These enzymes are used to digest complex molecules in a cell. When released into the cytoplasm, these enzymes can \"digest\" or destroy the cell itself. Therefore, they are called \"suicide bags.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>7","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"The process that brings about the shrinking of a Spirogyra cell when placed in a strong solution is","images":[],"options":{"A":"osmosis","B":"autolysis","C":"plasmolysis","D":"diffusion"},"answer":"C","explanation":"When a Spirogyra cell is placed in a strong (hypertonic) solution, water moves out of the cell due to osmosis, causing the cell to shrink. This process is known as plasmolysis. Osmosis is the movement of water molecules from an area of high concentration to an area of low concentration through a semi-permeable membrane. Autolysis is the self-destruction of cells by its own enzymes, and diffusion is the movement of particles from an area of high concentration to an area of low concentration, hence these options are not correct.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>8","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The region of a plant stem in which cells divide to increase its diameter is the","images":[],"options":{"A":"cambium","B":"phloem","C":"xylem","D":"collenchyma"},"answer":"A","explanation":"The vascular cambium is responsible for increasing the diameter of stems and roots and for forming woody tissue. The cork cambium produces some of the bark.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>9","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"The total number of caudal vertebrae in animals X and Y is 4 and 27 respectively. The animals are likely to be","images":[],"options":{"A":"fish and human.","B":"toad and rat","C":"toad and fish.","D":"humans and rat"},"answer":"D","explanation":"The number of caudal (tail) vertebrae varies among different animal species. Humans typically have 3 to 5 caudal vertebrae, which are fused to form the coccyx or tailbone. Rats, on the other hand, have a long tail with up to 28 caudal vertebrae. Therefore, the animals X and Y are likely to be humans and rats, respectively. Fish and toads do not have such a number of caudal vertebrae, and the number of caudal vertebrae in humans is not as high as 27.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>10","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following blood components has the greatest affinity for oxygen and carbon (IV) oxide?","images":[],"options":{"A":"Lymphocyte","B":"Erythrocyte","C":"Blood plasma","D":"Thrombocyte"},"answer":"B","explanation":"Erythrocyte is a red blood cell, which (in humans) is typically a biconcave disc without a nucleus. Erythrocytes contain the pigment haemoglobin, which imparts the red colour to blood, and transport oxygen and carbon dioxide to and from the tissues.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>11","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Use the following processes to answer the question below.  I - Ribs move upward and outward  II - Diaphragm relaxes  III -Volume of thorax increases  IV - Air is forced out of the lungs    Which of the processes take place during inspiration?","images":[],"options":{"A":"I and III only","B":"II and III only","C":"II and IV only","D":"III and IV only"},"answer":"A","explanation":"When the lungs inhale, the diaphragm contracts and pulls downward. At the same time, the muscles between the ribs contract and pull upward. This increases the size of the thoracic cavity and decreases the pressure inside. As a result, air rushes in and fills the lungs.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>12","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Use the following processes to answer the question below.  I - Ribs move upward and outward  II - Diaphragm relaxes  III -Volume of thorax increases  IV - Air is forced out of the lungs   Which of the processes is a direct result of contraction of the intercostal muscles?","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"B","explanation":"When the internal intercostal muscles contract and diaphragm relax, the ribs move downward and inward and the diaphragm becomes convex {dome shaped)","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>13","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : REGULATION OF INTERNAL ENVIRONMENT (HOMEOSTASIS)","question":"The process by which the amount of water and solutes in the blood are controlled is known as","images":[],"options":{"A":"haemolysis","B":"diffusion","C":"turgidity","D":"osmoregulation"},"answer":"D","explanation":"Osmoregulation is the process of maintaining salt and water balance (osmotic balance) across membranes within the body. The fluids inside and surrounding cells are composed of water, electrolytes, and nonelectrolytes","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>14","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"The table below shows the effect of hormones  I, II, III and IV on some parts of the human body. Where (\u221a) represents effect and (X) represents no effect of hormone on the corresponding part of the body. Study it and answer the question below  Hormone Effect on HeartEffect on Digestive systemEffect on KidneyEffect on UterusI\u221a\u221a\u221a\u221a IIXX\u221aXIIIXXX\u221aIVX\u221aXX    -Which of the following hormones are I, II, III and IV respectively?","images":[],"options":{"A":"ADH, Glucagon, Oestrogen, Adrenaline","B":"Adrenaline, Glucagon, Oestrogen, ADH","C":"Glucagon, ADH, Oestrogen, Adrenaline","D":"Adrenaline, ADH, Oestrogen, Glucagon"},"answer":"D","explanation":"Adrenaline- increases blood pressure, heart rate, and metabolism in reaction to stress        ADH-Antidiuretic hormone (ADH) helps regulate the amount of water in your body. It works to control the amount of water your kidneys reabsorb as they filter out waste from your blood. This hormone is also called arginine vasopressin (AVP).  Oestrogen is a female sex hormone that has many roles in the body, from controlling puberty to strengthening bones.  Glucagon is a hormone that is involved in controlling blood sugar (glucose) levels.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2022>15","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"The table below shows the effect of hormones  I, II, III and IV on some parts of the human body. Where (\u221a) represents effect and (X) represents no effect of hormone on the corresponding part of the body. Study it and answer the question below  Hormone Effect on HeartEffect on Digestive systemEffect on KidneyEffect on UterusI\u221a\u221a\u221a\u221a IIXX\u221aXIIIXXX\u221aIVX\u221aXXThe hormone responsible for anxiety is","images":[],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Anxiety can be caused by your body initiating its fight-or-flight response due to stress or even just due to anxious thoughts. This response produces adrenaline, which prepares your body for danger. Adrenaline causes many of the symptoms you experience with anxiety","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>16","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The diagram below is an illustration of  some parts of a mammalian ear. Study it and answer the question below.        The parts labelled I are the","images":["data:image/png;base64,"],"options":{"A":"semi circular canals.","B":"ossicles","C":"cochlea","D":"external auditory meatus."},"answer":"B","explanation":"The ossicles are actually tiny bones - the smallest in the human body. The three bones are named after their shapes: the malleus (hammer), incus (anvil) and stapes (stirrup). The ossicles further amplify the sound.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>17","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The diagram below is an illustration of  some parts of a mammalian ear. Study it and answer the question below.     Which of the parts are correctly grouped?  Inner ear\tMiddle ear\tOuter ear","images":["data:image/png;base64,"],"options":{"A":"I  IV,\tIII,\t     II","B":"III,\t II  IV,\t      I","C":"I,               II,                 III   IV","D":"II,\t  I   III,\t        IV"},"answer":"D","explanation":"The inner ear is made up of the cochlea, the auditory nerve and the brain. The middle ear consists of the middle ear bones called the ossicles (malleus, incus, stapes). The outer ear includes the pinna, the ear canal and the eardrum.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>18","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The diagram below is an illustration of  some parts of a mammalian ear. Study it and answer the question below.     The middle ear is connected to the pharynx by the part labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"C","explanation":"The Eustachian tube connects the middle ear space to the upper part of the throat.","marks":"1","difficulty":"3"},{"id":"objective>Biology>2022>19","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagrams below are illustrations of two different cells involved in a biological process in mammals. Study them and answer the question below.      Which parts of P and Q fuse to complete the biological process?","images":["data:image/png;base64,"],"options":{"A":"III and I","B":"IV and I","C":"III and II","D":"IV and II"},"answer":"A","explanation":"When the sperm cell finally reaches the egg cell, the plasma membranes of the two cells fuse together","marks":"1","difficulty":"3"},{"id":"objective>Biology>2022>20","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The diagrams below are illustrations of two different cells involved in a biological process in mammals. Study them and answer the question below.   Which of the following statements about P and Q is correct?","images":["data:image/png;base64,"],"options":{"A":"Both cells are structures for asexual reproduction","B":"Both cells normally belong to the same individual","C":"Both cells are found in plants","D":"The union of both cells gives rise to a new mammal"},"answer":"D","explanation":"Fertilization is the process in which gametes (an egg and sperm) fuse to form a zygote","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>21","subject":"Biology","year":"2022","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"The diagrams below are illustrations of two different cells involved in a biological process in mammals. Study them and answer the question below.   If the number of chromosomes in the skin cells of mammals is 46, how many chromosomes would be found in P and Q respectively?","images":["data:image/png;base64,"],"options":{"A":"23 and 23","B":"23 and 46","C":"46 and 23","D":"46 and 46"},"answer":"A","explanation":"A gamete is a mature haploid (having half the number of chromosomes i.e., 23 chromosomes) male or female germ cell which is able to unite with another of the opposite sex in sexual reproduction to form a diploid (having the complete number of chromosomes i.e., 46 chromosomes) zygote, which results in Fertilisation.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>22","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"In which of the following structures is simple sugar produced?","images":[],"options":{"A":"Vacuole","B":"Cytoplasm","C":"Chloroplast","D":"Cell wall"},"answer":"C","explanation":"Plants can produce their own food. During the process of photosynthesis they use water sunlight, carbon dioxide and sunlight to produce simple sugar and also release oxygen in the environment. The most common sugars are glucose, fructose and sucrose.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>23","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ENERGY TRANSFORMATION IN NATURE","question":"An evidence of the occurrence of photosynthesis in an experiment is the","images":[],"options":{"A":"release of carbon (IV) oxide.","B":"release of oxygen.","C":"formation of water molecules.","D":"formation and release of fructose."},"answer":"B","explanation":"The release of oxygen is a direct evidence of the occurrence of photosynthesis. During photosynthesis, plants take in carbon dioxide and water, and with the help of sunlight, they convert these into glucose and oxygen. The oxygen is released into the atmosphere, which is a visible sign that photosynthesis is taking place.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>24","subject":"Biology","year":"2022","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"The major sources of vitamin A are","images":[],"options":{"A":"egg yolk, carrot and palm oil.","B":"mango, pawpaw and eggs.","C":"sorghum, soya bean and liver.","D":"rice bran, green vegetables and milk."},"answer":"A","explanation":"Vitamin A is a fat-soluble vitamin that is good for healthy vision, skin, bones and other tissues in the body. Vitamin A often works as an antioxidant, fighting cell damage, but it also has many other uses. Some of the major sources of Vitamin A are egg yolk, carrot and palm oil. Egg yolk is a rich source of Vitamin A. Carrots are high in beta carotene, a compound our bodies change into vitamin A. Palm oil is also rich in beta carotene.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>25","subject":"Biology","year":"2022","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Diagram J is a protease while diagrams K, L,M and N are food substances. Study them and answer question the question below      Which of the illustrated food substances would form a reaction with protease J?","images":["data:image/png;base64,"],"options":{"A":"K","B":"L","C":"M","D":"N"},"answer":"B","explanation":"Diagram L would form a reaction with protease J because of the shape of L which will fit into the hollow shape of diagram J","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>26","subject":"Biology","year":"2022","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Diagram J is a protease while diagrams K, L,M and N are food substances. Study them and answer question the question below   Protease J would react with the particular illustrated substance because enzymes","images":["data:image/png;base64,"],"options":{"A":"are denatured at a high frequency.","B":"are specific in their action.","C":"remain unchanged after a reaction.","D":"speed up the rate of chemical reaction."},"answer":"B","explanation":"Enzymes, such as proteases, have specific shapes that fit only particular substrates, similar to a lock and key mechanism. This specificity ensures that each enzyme reacts only with a specific substance.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>27","subject":"Biology","year":"2022","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Diagram J is a protease while diagrams K, L,M and N are food substances. Study them and answer question the question below   After a reaction between protease J and the food substance, the end-product would be","images":["data:image/png;base64,"],"options":{"A":"fatty acids.","B":"glucose.","C":"amino acids.","D":"water."},"answer":"C","explanation":"protease (also called a peptidase or proteinase) is an enzyme that catalyzes (increases reaction rate or \"speeds up\") proteolysis, breaking down proteins into smaller polypeptides or single amino acids, and spurring the formation of new protein products.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>28","subject":"Biology","year":"2022","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The property of clayey soil that prevents it from supporting thick vegetation is its","images":[],"options":{"A":"composition of chemically weathered granite rocks.","B":"inability to retain much water.","C":"tendency of becoming waterlogged.","D":"porosity and low water-retention ability."},"answer":"C","explanation":"Clayey soil is a type of soil that is characterized by small particle size and high capacity for holding water. This property makes it prone to becoming waterlogged, especially during heavy rains. When soil is waterlogged, the water fills up all the air spaces between the soil particles, leaving no room for air. This lack of air can suffocate roots of plants and can cause them to rot, which can make it difficult for thick vegetation to grow. Therefore, the property of clayey soil that prevents it from supporting thick vegetation is its tendency of becoming waterlogged.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>29","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Which of the following practices will not maintain soil fertility?","images":[],"options":{"A":"Preventing soil erosion","B":"Bush fallowing","C":"Leaving the land bare","D":"Planting cover crops"},"answer":"C","explanation":"Leaving the land bare will not maintain soil fertility. This is because when the land is left bare, it is exposed to the elements, which can lead to soil erosion and the loss of nutrients. Soil erosion is the process where wind, water, or other natural agents move soil from one place to another, causing the fertile topsoil to be washed or blown away. This can lead to a decrease in soil fertility as the topsoil contains the majority of the soil's nutrients and organic matter.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>30","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : POPULATION STUDIES BY SAMPLING","question":"A group of organisms of the same species living in a particular place is known as","images":[],"options":{"A":"colony.","B":"community.","C":"ecosystem.","D":"population."},"answer":"D","explanation":"A population is the number of organisms of the same species that live in a particular geographic area at the same time, with the capability of interbreeding.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>31","subject":"Biology","year":"2022","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The diagram below is an illustration of an experiment on sedimentation of soil. Use it to answer the question below       The organic component of the soil is labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"The organic component of the soil is labelled I. Organic component forms the topmost layer","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>32","subject":"Biology","year":"2022","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The diagram below is an illustration of an experiment on sedimentation of soil. Use it to answer the question below    The part labelled IV is","images":["data:image/png;base64,"],"options":{"A":"silt.","B":"sand.","C":"humus.","D":"clay."},"answer":"B","explanation":"The part labelled IV is sand. Sand particles settles at the bottom.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>33","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Which of the following pyramids is not used in ecology? Pyramid of","images":[],"options":{"A":"energy","B":"numbers","C":"biomass","D":"organisms"},"answer":"D","explanation":"An ecological pyramid is a graphical representation showing the relationship between different organisms in an ecosystem. It shows the flow of energy at different trophic levels in an ecosystem.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>34","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Study the food chain illustrated below and use it to answer the question below  J \u2192 K\u2192  L\u2192  M \u2192 N    Organism J is normally sustained by energy from","images":[],"options":{"A":"green plants.","B":"carbohydrates.","C":"organism K.","D":"sunlight"},"answer":"D","explanation":"The sun is the major source of energy for organisms and the ecosystem.J are producers which use the energy from the sunlight to make organic matter from carbon dioxide and water","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>35","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Study the food chain illustrated below and use it to answer the question below  J \u2192 K\u2192  L\u2192  M \u2192 N  Which of the following statements about organism L is correct? It","images":[],"options":{"A":"feeds on organism M","B":"is a primary consumer","C":"is the producer","D":"is a secondary consumer"},"answer":"D","explanation":"Secondary consumer are the group in the food chain that eats primary consumers. This means that secondary consumers can either be omnivores or carnivores.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>36","subject":"Biology","year":"2022","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Study the food chain illustrated below and use it to answer the question below  J \u2192 K\u2192  L\u2192  M \u2192 N  The position occupied by each of organisms  J, K, L, M and N in the food chain is known as the","images":[],"options":{"A":"energy level.","B":"trophic level.","C":"food web.","D":"pyramid of numbers."},"answer":"B","explanation":"The trophic level of an organism is the number of steps it is from the start of the chain. A trophic level is the group of organisms within an ecosystem which occupy the same level in a food chain.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>37","subject":"Biology","year":"2022","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.","question":"Which of the following features is not an adaptation of plants to aquatic habitats?","images":[],"options":{"A":"Breathing roots for entry of air","B":"Flowers are raised above water to attract pollinators","C":"Spongy tissues containing gases for buoyancy","D":"Hairy structures on the leaves to reduce water loss"},"answer":"D","explanation":"Aquatic plants are referred to as hydrophytes. Plants need special adaptations to exchange  gases, reproduce and mantain a balance of salt and water.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>38","subject":"Biology","year":"2022","type":"Objective","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"The biological association that contributes directly to succession in a community is","images":[],"options":{"A":"competition.","B":"predation.","C":"parasitism.","D":"commensalism"},"answer":"A","explanation":"Succession in a community is a process where the structure of a biological community evolves over time. This process is directly influenced by competition among species for resources. In this context, competition refers to the struggle between individuals or different species for limited resources. This competition leads to the survival of the fittest and contributes to the succession in a community. Predation, parasitism, and commensalism are also biological associations, but they do not contribute directly to succession.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>39","subject":"Biology","year":"2022","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : WAYS OF ENSURING CONSERVATION","question":"The conservation of natural resources is enhanced by the following practices except","images":[],"options":{"A":"controlling farming activities.","B":"protecting endangered species.","C":"poaching in game reserves","D":"establishing parks and gardens."},"answer":"C","explanation":"The conservation of natural resources is a practice that involves protecting, preserving, and managing the use of our natural resources in a sustainable way. This includes controlling farming activities to prevent soil erosion and degradation, protecting endangered species to maintain biodiversity, and establishing parks and gardens to preserve natural habitats. However, poaching in game reserves is not a conservation practice. Instead, it is a harmful activity that threatens wildlife populations and disrupts ecosystems.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>40","subject":"Biology","year":"2022","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The burning of farmlands should be discouraged because it","images":[],"options":{"A":"destroys the organic components of the soil.","B":"increases the population of wild animals on the farm.","C":"increases the dormancy period of some seeds.","D":"destroys some plant pests."},"answer":"A","explanation":"During burning process some nutrients that are highly needed by the plants are lost out in form of gases such nutrients include phosphorus, nitrogen and sulphur. It destroy soil organisms, soil texture and soil fertility and expose the soil to erosion.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>41","subject":"Biology","year":"2022","type":"Objective","topic":"CONSERVATION OF NATURAL RESOURCES : SOIL, WATER, WILDLIFE, FOREST AND MINERALS","question":"The use of a lighter instead of match sticks is a way of conserving","images":[],"options":{"A":"petroleum","B":"forest","C":"water","D":"wildlife"},"answer":"B","explanation":"Forest conservation is the practice of planting more trees and maintaining the forested areas for the sustainability for future generations. The conservation of forest also stands and aims at a quick shift in the composition of trees species and age distribution.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>42","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"An accident victim was successfully transfused with blood from the father whose blood, group is AB. The blood group of the accident victim is","images":[],"options":{"A":"B","B":"O","C":"AB","D":"A"},"answer":"C","explanation":"In blood transfusion, the recipient's blood group should be compatible with the donor's blood group. Blood group AB is a universal recipient, meaning a person with AB blood group can receive blood from any group (A, B, AB, or O). Therefore, if the accident victim was successfully transfused with blood from the father whose blood group is AB, the blood group of the accident victim could be AB.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>43","subject":"Biology","year":"2022","type":"Objective","topic":"VARIATION IN POPULATION : PHYSIOLOGICAL VARIATIONS","question":"Which of the following traits in humans is an example of physiological variation?","images":[],"options":{"A":"Skin colour","B":"Fingerprint","C":"Tongue rolling","D":"Height"},"answer":"C","explanation":"other options are morphological variation.  The ability of man to roll their tongue is characterized under physiological variation. Physiological variation relates to the differences in the ways individuals of the same species behave or react to conditions in their environment.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>44","subject":"Biology","year":"2022","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Individuals belonging to blood group 0 are universal donors because","images":[],"options":{"A":"antigens are absent in their blood cells.","B":"members of the group constitute the  highest number of humans.","C":"there are no antibodies in their blood plasma.","D":"the antigens in their blood cells are easily destroyed."},"answer":"A","explanation":"Blood group O does not have A or B antigens on the surface of their red blood cells, and therefore, their blood can be donated to individuals of any ABO blood group without causing an immune response.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>45","subject":"Biology","year":"2022","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"Two tall plants were crossed and all the F1 plants were tall. When the F1 plants were selfed, some of the F2 plants were tall while others were short. What are the possible genotypes of the original plants?","images":[],"options":{"A":"Tt and tt","B":"TT and TT","C":"tt and tt","D":"TT and Tt"},"answer":"D","explanation":"Mendel crossed pure tall plant(TT) with a pure dwarf plant(tt). In the F1 generation, tall plants are formed(Tt). When F1 plant is subjected to self pollination, in the F2 generation, 3 tall plants and 1 dwarf plants are formed. In the one homozygous tall plant(TT), 2 heterozygous tall plants(Tt), one homozygous dwarf plant(tt) are formed","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>46","subject":"Biology","year":"2022","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : GENETIC TERMINOLOGIES","question":"Which of the following statements best describes a test cross? It is","images":[],"options":{"A":"to determine the genotype of an individual whose phenotype is known","B":"to determine the phenotype of an individual whose genotype is known","C":"between the progeny of parents to ascertain their external expressions","D":"between two homozygous recessive individuals to confirm the genotypes of the offspring"},"answer":"A","explanation":"A test cross is a way to determine the genotype of an individual whose phenotype is known. This is done by crossing the individual with an organism that is homozygous recessive for the trait in question. If any of the offspring display the recessive phenotype, the individual must be heterozygous. If all offspring display the dominant phenotype, the individual is likely homozygous dominant.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>47","subject":"Biology","year":"2022","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : LINKAGE, SEX DETERMINATION AND SEX LINKED CHARACTERS","question":"Which of the following statements about sex-linked traits is not correct?","images":[],"options":{"A":"Males inherit sex-linked traits from their fathers","B":"Sex-linked traits are more common in males","C":"Females can be carriers because they can be heterozygous for the trait","D":"Males are never carriers since they only receive one sex chromosome"},"answer":"A","explanation":"This statement is not correct. Males inherit their X chromosome (which carries the majority of sex-linked traits) from their mothers and their Y chromosome from their fathers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>48","subject":"Biology","year":"2022","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : APPLICATION OF THE PRINCIPLES OF HEREDITY","question":"When two carriers of sickle cell anaemia produce an offspring, the probability of the offspring being a sickler is","images":[],"options":{"A":"3/4","B":"1/4","C":"1/2","D":"2/3"},"answer":"B","explanation":"Sickle cell anemia is a genetic disorder that is inherited in an autosomal recessive manner. This means that an individual must inherit two copies of the sickle cell gene (one from each parent) in order to have the disease. If both parents are carriers of the sickle cell gene (meaning they each have one copy of the gene), then there is a 1/4 chance with each pregnancy that the child will inherit two copies of the gene and have sickle cell anemia.","marks":"1","difficulty":"1"},{"id":"objective>Biology>2022>49","subject":"Biology","year":"2022","type":"Objective","topic":"EVOLUTION : ADAPTIVE COLOURATION","question":"Which of the following organisms exhibits adaptive colouration?","images":[],"options":{"A":"Rabbit","B":"Chameleon","C":"Mouse","D":"Dog"},"answer":"B","explanation":"Adaptive coloration is a type of camouflage where an organism's coloration pattern helps it blend in with its environment to avoid detection by predators or prey. Chameleons are known for their ability to change their skin color to match their surroundings, which is a clear example of adaptive coloration.","marks":"1","difficulty":"2"},{"id":"objective>Biology>2022>50","subject":"Biology","year":"2022","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : EVOLUTION","question":"Which of the following sequences is the correct evolutionary trend in organisms?","images":[],"options":{"A":"Algae---->Liverwort---->Ferns---->Angiosperms","B":"Liverwort---->Angiosperm---->Ferns---->Algae","C":"Angiosperms---->Algae---->Ferns---->Liverwort","D":"Ferns---->Liverwort---->Angiosperms---->Algae"},"answer":"A","explanation":"The continous change of the characters within an evoving lineage is called evolutinary trend. A lineage is an evolutionary sequence. Arranged in linear order from an ancestral group to descendant group.","marks":"1","difficulty":"2"}];